    // Arrange
    String fileName = "testFile.txt";
    String fileContent = "Hello, this is the file content.";

    // Mock getResourceFile to return a dummy File (not used directly since ZipFile is mocked)
    File dummyFile = mock(File.class);

    // Mock static method getResourceFile
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
