        // 2. But resourceToString is private static, so cannot override easily.
        // 3. So we will use reflection to invoke resourceToString and mock ZipFile constructor using Mockito inline mock maker.

        // Since mocking ZipFile constructor is not possible here, we will do a workaround by creating a temporary zip file on disk.

        // Create temporary zip file with the entry and content
        java.nio.file.Path tempZipPath = java.nio.file.Files.createTempFile("ParseBenchmarkData", ".zip");
        try (java.util.zip.ZipOutputStream zos = new java.util.zip.ZipOutputStream(java.nio.file.Files.newOutputStream(tempZipPath))) {
          zos.putNextEntry(new java.util.zip.ZipEntry(fileName));
          zos.write(fileContent.getBytes());
          zos.closeEntry();
